// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "${CONTRACT_PATH}";

interface IChainlinkOracle {
    function latestRoundData() external view returns (
        uint80 roundId,
        int256 answer,
        uint256 startedAt,
        uint256 updatedAt,
        uint80 answeredInRound
    );
}

contract OracleManipulationTest is Test {
    ${CONTRACT_NAME} public target;
    address public oracle;

    function setUp() public {
        target = ${CONTRACT_NAME}(${CONTRACT_ADDRESS});
        oracle = ${ORACLE_ADDRESS};
    }

    function testOracleManipulation() public {
        // Get current price
        (, int256 priceBefore,,,) = IChainlinkOracle(oracle).latestRoundData();

        // Mock a manipulated price (50% drop)
        int256 manipulatedPrice = priceBefore / 2;

        vm.mockCall(
            oracle,
            abi.encodeWithSelector(IChainlinkOracle.latestRoundData.selector),
            abi.encode(uint80(1), manipulatedPrice, block.timestamp, block.timestamp, uint80(1))
        );

        // Try to exploit with manipulated price
        // Add exploit logic here based on function
    }

    function testStalePrice() public {
        // Mock stale price (1 day old)
        uint256 staleTimestamp = block.timestamp - 1 days;

        vm.mockCall(
            oracle,
            abi.encodeWithSelector(IChainlinkOracle.latestRoundData.selector),
            abi.encode(uint80(1), int256(1000e8), staleTimestamp, staleTimestamp, uint80(1))
        );

        // If this doesn't revert, contract accepts stale prices
        target.${FUNCTION_NAME}();
    }
}
